import Link from 'next/link'
import { Home, Inbox, ClipboardList, PlusCircle } from 'lucide-react'
import { useStore } from '../store/useStore'

export default function Sidebar(){
  const user = useStore(s=>s.user)

  // patient see only basic navigation; staff see full menu
  const isPatient = user && user.role === 'patient'

  return (
    <aside className="w-64 p-4 border-r h-screen sticky top-0 hidden md:block">
      <div className="mb-6">
        <div className="text-2xl font-bold" style={{color:'#0ea5e9'}}>MediFlow Hub</div>
        <div className="text-sm text-gray-500">Inter-department Workflow</div>
      </div>
      <nav className="space-y-2">
        {isPatient ? (
          <>            
            <Link href="/patient" className="flex items-center gap-2 p-2 rounded hover:bg-gray-100">
              <Home /> Home
            </Link>
            <Link href="/patient" className="flex items-center gap-2 p-2 rounded hover:bg-gray-100">
              <PlusCircle /> New Request
            </Link>
          </>
        ) : (
          <>            
            <Link href="/dashboard" className="flex items-center gap-2 p-2 rounded hover:bg-gray-100">
              <Home /> Home
            </Link>
            <Link href="/dashboard" className="flex items-center gap-2 p-2 rounded hover:bg-gray-100">
              <Inbox /> My Department
            </Link>
            <Link href="/requests/REQ-1001" className="flex items-center gap-2 p-2 rounded hover:bg-gray-100">
              <ClipboardList /> All Requests
            </Link>
          </>
        )}
      </nav>
    </aside>
  )
}
